pub struct PTDirView {
    pub region: MemRegion,
    pub entries: Seq<Option<PTDirView>>,
    pub used_regions: Set<MemRegion>,
}

impl View for PTDir {
    type V = PTDirView;
    closed spec fn view(&self) -> PTDirView {
        PTDirView {
            region: self.region,
            entries: self.entries@,
            used_regions: self.used_regions,
        }
    }
}

pub enum LoadResultView {
    Pagefault,
    Value(Seq<u8>),
}

impl View for LoadResult {
    type V = LoadResultView;
    closed spec fn view(&self) -> LoadResultView {
        match self {
            LoadResult::Pagefault => LoadResultView::Pagefault,
            LoadResult::Value(s) => LoadResultView::Value(s@),
        }
    }
}

pub struct WrappedMapTokenView {
    pub tok: <crate::os_code_vc::Token as View>::V,
    pub change_made: bool,
    pub orig_st: <os::State as View>::V,
}

impl View for WrappedMapToken {
    type V = WrappedMapTokenView;
    closed spec fn view(&self) -> WrappedMapTokenView {
        WrappedMapTokenView {
            tok: self.tok@,
            change_made: self.change_made,
            orig_st: self.orig_st@,
        }
    }
}
